typedef enum SDL_FlipMode
{
 SDL_FLIP_NONE, /**< تشير هذه القيمة إلى NONE، وتُستخدم داخل التعداد SDL_FlipMode ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_FLIP_HORIZONTAL, /**< تشير هذه القيمة إلى HORIZONTAL، وتُستخدم داخل التعداد SDL_FlipMode ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_FLIP_VERTICAL, /**< تشير هذه القيمة إلى VERTICAL، وتُستخدم داخل التعداد SDL_FlipMode ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_FLIP_HORIZONTAL_AND_VERTICAL = (SDL_FLIP_HORIZONTAL | SDL_FLIP_VERTICAL) /**< تشير هذه القيمة إلى HORIZONTAL AND VERTICAL، وتُستخدم داخل التعداد SDL_FlipMode ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
} SDL_FlipMode;
